sql:
SELECT DISTINCT e.event_name, e.location, e.start_date, e.end_date, e.registration_fee, a.affiliation_code, a.contact_email, a.website_url
FROM events e
JOIN affiliations a ON e.organizer = a.affiliation_name;

external_knowledge:
- 'Event Name': Specific event title as mentioned in the event database;
- 'Category Name': Refers to the particular division or group of participants such as 'junior' or 'senior';
- 'Top Contenders': Participants who have achieved higher total scores in the event;
- 'Overall Performance Metrics': Refers to the total score which is a sum of different scores and penalties.
